SELECT DISTINCT user_name
FROM users
WHERE user_id IN (SELECT user_id FROM notifications);

SELECT import_status
FROM data_imports
WHERE imported_by = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT vax_name, efficacy_rate, SUM(LENGTH(efficacy_rate)) AS total_length
FROM vaccination_status
WHERE vax_name = 'Fully vaccinated';
